    def __init__(self):
        self.board = [[' ' for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in range((i + 1) % 2, 8, 2):
                self.board[i][j] = 'B'
        for i in range(5, 8):
            for j in range(i % 2, 8, 2):
                self.board[i][j] = 'W'

    def display_board(self):
        print("  a b c d e f g h")
        for i, row in enumerate(self.board):
            print(f"{i + 1} {' '.join(row)}")

    def move_piece(self, from_pos, to_pos):
        piece = self.get_piece(from_pos)
        if piece:
            self.set_piece(to_pos, piece)
            self.clear_piece(from_pos)

    def get_piece(self, pos):
        return self.board[int(pos[1]) - 1][ord(pos[0]) - ord('a')]

    def set_piece(self, pos, piece):
        self.board[int(pos[1]) - 1][ord(pos[0]) - ord('a')] = piece

    def clear_piece(self, pos):
        self.board[int(pos[1]) - 1][ord(pos[0]) - ord('a')] = ' '
